/**
 * Represents a bounding rectangle with top, bottom, left, and right coordinates.
 * @public
 * @unofficial
 */
export interface Coords {
    /** Bottom edge coordinate. */
    bottom: number;

    /** Left edge coordinate. */
    left: number;

    /** Right edge coordinate. */
    right: number;

    /** Top edge coordinate. */
    top: number;
}
